@Service
@EnableAsync
public class EmailService {

    @Async
    public CompletableFuture<Void> sendWelcomeEmail(User user) {
        String html = emailTemplate.render("welcome", user);
        mailSender.send(user.getEmail(), "Welcome!", html);
        return CompletableFuture.completedFuture(null);
    }

    @Async
    public CompletableFuture<Void> sendPasswordReset(String email, String token) {
        mailSender.send(email, "Password Reset",
            "Click here to reset: http://example.com/reset?token=" + token);
        return CompletableFuture.completedFuture(null);
    }

    public void registerUser(User user) {
        userRepository.save(user);
        sendWelcomeEmail(user); // Runs asynchronously
    }
}
